import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './ProductDetail.css';

function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showInquiry, setShowInquiry] = useState(false);
  const [inquiryData, setInquiryData] = useState({
    name: '',
    email: '',
    phone: '',
    message: '',
    quantity: ''
  });
  const [inquirySent, setInquirySent] = useState(false);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const res = await axios.get(`/api/products/${id}`);
        setProduct(res.data);
      } catch (err) {
        console.error('Error fetching product', err);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  if (loading) return <div className="loading">Loading...</div>;
  if (!product) return <div className="loading">Product not found.</div>;

  return (
    <div className="product-detail">
      <div className="container">
        <div className="detail-card">
          <div className="detail-image">
            {product.image_url ? (
              <img src={product.image_url} alt={product.name} />
            ) : (
              <div className="product-placeholder">No Image</div>
            )}
          </div>
          <div className="detail-info">
            <h1>{product.name}</h1>
            <p className="detail-price">
              ₹{product.price?.toLocaleString() || 'Price on Request'}
            </p>
            <p className="detail-location">{product.location}</p>
            <p className="detail-description">{product.description}</p>

            <div className="detail-meta">
              <p><strong>Category:</strong> {product.category_name || 'N/A'}</p>
              <p><strong>Supplier:</strong> {product.company_name}</p>
              <p><strong>About Supplier:</strong> {product.company_description}</p>
            </div>

            <div className="detail-actions">
              <button 
                onClick={() => {
                  const token = localStorage.getItem('token');
                  if (token) {
                    setShowInquiry(true);
                  } else {
                    navigate('/login');
                  }
                }}
                className="btn btn-primary"
              >
                Send Inquiry
              </button>
              <Link to={`/suppliers/${product.company_id}`} className="btn btn-outline">View Supplier Profile</Link>
              <Link to="/products" className="btn btn-secondary">Back to Products</Link>
            </div>
            
            {showInquiry && !inquirySent && (
              <div className="inquiry-form">
                <h3>Send Inquiry to Supplier</h3>
                <form onSubmit={handleSendInquiry}>
                  <div className="input-group">
                    <label>Your Name *</label>
                    <input
                      type="text"
                      required
                      value={inquiryData.name}
                      onChange={(e) => setInquiryData({...inquiryData, name: e.target.value})}
                    />
                  </div>
                  <div className="input-group">
                    <label>Email *</label>
                    <input
                      type="email"
                      required
                      value={inquiryData.email}
                      onChange={(e) => setInquiryData({...inquiryData, email: e.target.value})}
                    />
                  </div>
                  <div className="input-group">
                    <label>Phone *</label>
                    <input
                      type="tel"
                      required
                      value={inquiryData.phone}
                      onChange={(e) => setInquiryData({...inquiryData, phone: e.target.value})}
                    />
                  </div>
                  <div className="input-group">
                    <label>Quantity Required</label>
                    <input
                      type="text"
                      value={inquiryData.quantity}
                      onChange={(e) => setInquiryData({...inquiryData, quantity: e.target.value})}
                      placeholder="e.g., 100 units"
                    />
                  </div>
                  <div className="input-group">
                    <label>Message *</label>
                    <textarea
                      required
                      value={inquiryData.message}
                      onChange={(e) => setInquiryData({...inquiryData, message: e.target.value})}
                      placeholder="Tell the supplier about your requirements..."
                    />
                  </div>
                  <div className="form-actions">
                    <button type="submit" className="btn btn-primary">Send Inquiry</button>
                    <button type="button" onClick={() => setShowInquiry(false)} className="btn btn-secondary">Cancel</button>
                  </div>
                </form>
              </div>
            )}
            
            {inquirySent && (
              <div className="success">
                <p>Your inquiry has been sent successfully! The supplier will contact you soon.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default ProductDetail;
